  1→//! Docker and Podman sandbox backends.
  2→
  3→use {
  4→    async_trait::async_trait,
  5→    tracing::{debug, info, warn},
  6→};
  7→
  8→use {
  9→    super::{
 10→        containers::{
 11→            rebuildable_sandbox_image_tag, sandbox_image_dockerfile, sandbox_image_exists,
 12→            sandbox_image_tag,
 13→        },
 14→        host::provision_packages,
 15→        paths::{
 16→            ensure_sandbox_home_persistence_host_dir, host_visible_data_dir,
 17→            resolve_home_persistence_guest_path_on_host, resolve_workspace_guest_path_on_host,
 18→        },
 19→        types::{
 20→            BuildImageResult, DEFAULT_SANDBOX_IMAGE, NetworkPolicy, SANDBOX_HOME_DIR, Sandbox,
 21→            SandboxConfig, SandboxId, WorkspaceMount, canonical_sandbox_packages,
 22→            truncate_output_for_display,
 23→        },
 24→    },
 25→    crate::{
 26→        error::{Error, Result},
 27→        exec::{ExecOpts, ExecResult},
 28→        sandbox::file_system::{
 29→            SandboxListFilesResult, SandboxReadResult, native_host_list_files,
 30→            native_host_read_file, native_host_write_file, oci_container_list_files,
 31→            oci_container_read_file, oci_container_write_file, remap_host_list_result_to_guest,
 32→        },
