 35→
 36→/// Docker/Podman-based sandbox implementation.
 37→///
 38→/// The `cli` field selects the container CLI binary (`"docker"` or `"podman"`).
 39→/// Podman's CLI is a drop-in replacement for Docker, so both backends share
 40→/// this single implementation.
 41→pub struct DockerSandbox {
 42→    pub config: SandboxConfig,
 43→    cli: &'static str,
 44→    backend_label: &'static str,
 45→}
 46→
 47→impl DockerSandbox {
 48→    pub fn new(config: SandboxConfig) -> Self {
 49→        Self {
 50→            config,
 51→            cli: "docker",
 52→            backend_label: "docker",
 53→        }
 54→    }
 55→
 56→    pub fn podman(config: SandboxConfig) -> Self {
 57→        Self {
 58→            config,
 59→            cli: "podman",
 60→            backend_label: "podman",
 61→        }
 62→    }
 63→
 64→    fn image(&self) -> &str {
 65→        self.config
 66→            .image
 67→            .as_deref()
 68→            .unwrap_or(DEFAULT_SANDBOX_IMAGE)
 69→    }
 70→
 71→    fn container_prefix(&self) -> &str {
 72→        self.config
 73→            .container_prefix
 74→            .as_deref()
 75→            .unwrap_or("moltis-sandbox")
 76→    }
 77→
 78→    pub(crate) fn container_name(&self, id: &SandboxId) -> String {
 79→        format!("{}-{}", self.container_prefix(), id.key)
 80→    }
 81→
 82→    fn image_repo(&self) -> &str {
 83→        self.container_prefix()
 84→    }
 85→
 86→    fn mounted_host_path(&self, id: &SandboxId, guest_path: &str) -> Option<std::path::PathBuf> {
 87→        let guest_path = std::path::Path::new(guest_path);
 88→        resolve_workspace_guest_path_on_host(&self.config, Some(self.cli), guest_path).or_else(
 89→            || {
 90→                resolve_home_persistence_guest_path_on_host(
 91→                    &self.config,
 92→                    Some(self.cli),
 93→                    id,
 94→                    guest_path,
 95→                )
 96→            },
 97→        )
 98→    }
 99→
100→    pub(crate) fn resource_args(&self) -> Vec<String> {
101→        let mut args = Vec::new();
102→        let limits = &self.config.resource_limits;
103→        if let Some(ref mem) = limits.memory_limit {
104→            args.extend(["--memory".to_string(), mem.clone()]);
105→        }
106→        if let Some(cpu) = limits.cpu_quota {
107→            args.extend(["--cpus".to_string(), cpu.to_string()]);
108→        }
109→        if let Some(pids) = limits.pids_max {
110→            args.extend(["--pids-limit".to_string(), pids.to_string()]);
111→        }
112→        args
113→    }
114→
115→    pub(crate) fn network_run_args(&self) -> Vec<String> {
116→        match self.config.network {
117→            NetworkPolicy::Blocked => vec!["--network=none".to_string()],
118→            NetworkPolicy::Trusted => {
119→                // Ensure the container can reach the host proxy on all
120→                // platforms (Linux needs --add-host; macOS Docker Desktop
121→                // resolves host.docker.internal automatically).
122→                let gateway = self.resolve_host_gateway();
123→                vec![format!("--add-host=host.docker.internal:{gateway}")]
124→            },
125→            NetworkPolicy::Bypass => Vec::new(),
126→        }
127→    }
128→
129→    /// Resolve the IP that containers use to reach the host.
130→    ///
131→    /// Docker (and Podman >= 5.0) support the special `host-gateway` token in
132→    /// `--add-host`.  Older Podman versions reject it with:
133→    ///
134→    ///   Error: invalid IP address in add-host: "host-gateway"
135→    ///
136→    /// For those we resolve the address ourselves: rootless Podman (< 5.0) uses
137→    /// slirp4netns by default, which maps the host to `10.0.2.2`.  Rootful
138→    /// Podman uses a bridge whose gateway we can query via
139→    /// `podman network inspect`.
140→    pub(crate) fn resolve_host_gateway(&self) -> String {
141→        if self.cli != "podman" {
142→            return "host-gateway".to_string();
143→        }
144→
145→        if podman_supports_host_gateway() {
146→            return "host-gateway".to_string();
147→        }
148→
149→        // Podman < 5.0 — resolve the address manually.
150→        podman_resolve_host_ip().unwrap_or_else(|| {
151→            debug!(
152→                "could not resolve host gateway IP for podman; \
153→                 falling back to host-gateway (may fail)"
154→            );
155→            "host-gateway".to_string()
156→        })
157→    }
158→
159→    pub(crate) fn proxy_exec_env_args(&self) -> Vec<String> {
160→        if self.config.network != NetworkPolicy::Trusted {
161→            return Vec::new();
162→        }
163→        let proxy_url = format!(
164→            "http://host.docker.internal:{}",
165→            moltis_network_filter::DEFAULT_PROXY_PORT
166→        );
167→        let mut args = Vec::new();
168→        for key in ["HTTP_PROXY", "http_proxy", "HTTPS_PROXY", "https_proxy"] {
169→            args.extend(["-e".to_string(), format!("{key}={proxy_url}")]);
170→        }
171→        for key in ["NO_PROXY", "no_proxy"] {
172→            args.extend(["-e".to_string(), format!("{key}=localhost,127.0.0.1,::1")]);
173→        }
174→        args
175→    }
176→
177→    /// Security hardening flags for `docker run`.
178→    ///
179→    /// `is_prebuilt` controls whether `--read-only` is applied: prebuilt images
180→    /// already have packages baked in so the root FS can be read-only, while
181→    /// non-prebuilt images need a writable root for `apt-get` provisioning.
182→    pub(crate) fn hardening_args(is_prebuilt: bool) -> Vec<String> {
183→        let mut args = vec![
184→            "--cap-drop".to_string(),
185→            "ALL".to_string(),
186→            "--security-opt".to_string(),
187→            "no-new-privileges".to_string(),
188→            "--tmpfs".to_string(),
189→            "/tmp:rw,nosuid,size=256m".to_string(),
190→            "--tmpfs".to_string(),
191→            "/run:rw,nosuid,size=64m".to_string(),
192→        ];
193→        if is_prebuilt {
194→            args.push("--read-only".to_string());
195→        }
196→        args
197→    }
198→
199→    pub(crate) fn workspace_args(&self) -> Vec<String> {
200→        let guest_workspace_dir = moltis_config::data_dir();
201→        let host_workspace_dir = host_visible_data_dir(&self.config, Some(self.cli));
202→        let guest_workspace_dir_str = guest_workspace_dir.display().to_string();
203→        let host_workspace_dir_str = host_workspace_dir.display().to_string();
204→        match self.config.workspace_mount {
205→            WorkspaceMount::Ro => vec![
206→                "-v".to_string(),
207→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:ro"),
208→            ],
209→            WorkspaceMount::Rw => vec![
210→                "-v".to_string(),
211→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:rw"),
212→            ],
213→            WorkspaceMount::None => Vec::new(),
214→        }
215→    }
216→
217→    pub(crate) fn home_persistence_args(&self, id: &SandboxId) -> Result<Vec<String>> {
218→        let Some(host_dir) =
219→            ensure_sandbox_home_persistence_host_dir(&self.config, Some(self.cli), id)?
220→        else {
221→            return Ok(Vec::new());
222→        };
223→        let volume = format!("{}:{SANDBOX_HOME_DIR}:rw", host_dir.display());
224→        Ok(vec!["-v".to_string(), volume])
225→    }
226→
227→    async fn resolve_local_image(&self, requested_image: &str) -> Result<String> {
228→        if sandbox_image_exists(self.cli, requested_image).await {
229→            return Ok(requested_image.to_string());
230→        }
231→
232→        let base_image = self.image().to_string();
233→        let packages = self.config.packages.clone();
234→        let Some(rebuild_tag) = rebuildable_sandbox_image_tag(
235→            requested_image,
236→            self.image_repo(),
237→            &base_image,
238→            &packages,
239→        ) else {
240→            return Ok(requested_image.to_string());
241→        };
242→
243→        if requested_image == rebuild_tag {
244→            info!(
245→                image = requested_image,
246→                "sandbox image missing locally, rebuilding on demand"
247→            );
248→        } else {
249→            warn!(
250→                requested = requested_image,
251→                rebuilt = %rebuild_tag,
252→                "requested sandbox image missing locally, using deterministic tag from current config"
253→            );
254→        }
255→
256→        let Some(result) = self.build_image(&base_image, &packages).await? else {
257→            return Ok(requested_image.to_string());
258→        };
259→        Ok(result.tag)
260→    }
261→}
262→
263→#[async_trait]
264→impl Sandbox for DockerSandbox {
265→    fn backend_name(&self) -> &'static str {
266→        self.backend_label
267→    }
268→
269→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
270→        let name = self.container_name(id);
271→
272→        // Check if container already running.
273→        let check = tokio::process::Command::new(self.cli)
274→            .args(["inspect", "--format", "{{.State.Running}}", &name])
275→            .output()
276→            .await;
277→
278→        if let Ok(output) = check {
279→            let stdout = String::from_utf8_lossy(&output.stdout);
280→            if stdout.trim() == "true" {
281→                return Ok(());
282→            }
283→        }
284→
285→        // Resolve image first so we know whether it's prebuilt (affects hardening).
286→        let requested_image = image_override.unwrap_or_else(|| self.image());
287→        let image = self.resolve_local_image(requested_image).await?;
288→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
289→
290→        // Start a new container.
291→        let mut args = vec![
292→            "run".to_string(),
293→            "-d".to_string(),
294→            "--name".to_string(),
295→            name.clone(),
296→        ];
297→
298→        args.extend(self.network_run_args());
299→
300→        if let Some(ref tz) = self.config.timezone {
301→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
302→        }
303→
304→        args.extend(self.resource_args());
305→        args.extend(Self::hardening_args(is_prebuilt));
306→        args.extend(self.workspace_args());
307→        args.extend(self.home_persistence_args(id)?);
308→
309→        args.push(image.clone());
310→        args.extend(["sleep".to_string(), "infinity".to_string()]);
311→
312→        let output = tokio::process::Command::new(self.cli)
313→            .args(&args)
314→            .output()
315→            .await?;
316→
317→        if !output.status.success() {
318→            let stderr = String::from_utf8_lossy(&output.stderr);
319→            return Err(Error::message(format!(
320→                "{} run failed: {}",
321→                self.cli,
322→                stderr.trim()
323→            )));
324→        }
325→
326→        // Skip provisioning if the image is a pre-built instance sandbox image
327→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
328→        if !is_prebuilt {
329→            provision_packages(self.cli, &name, &self.config.packages).await?;
330→        }
331→
332→        Ok(())
333→    }
334→
335→    async fn build_image(
336→        &self,
337→        base: &str,
338→        packages: &[String],
339→    ) -> Result<Option<BuildImageResult>> {
340→        if packages.is_empty() {
341→            return Ok(None);
342→        }
343→
344→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
345→
346→        // Check if image already exists.
347→        if sandbox_image_exists(self.cli, &tag).await {
348→            info!(
349→                tag,
350→                "pre-built sandbox image already exists, skipping build"
351→            );
352→            return Ok(Some(BuildImageResult { tag, built: false }));
353→        }
354→
355→        // Generate Dockerfile in a temp dir.
356→        let tmp_dir =
357→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
358→        std::fs::create_dir_all(&tmp_dir)?;
359→
360→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
361→        let dockerfile = sandbox_image_dockerfile(base, packages);
362→        let dockerfile_path = tmp_dir.join("Dockerfile");
363→        std::fs::write(&dockerfile_path, &dockerfile)?;
364→
365→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
366→
367→        let output = tokio::process::Command::new(self.cli)
368→            .args(["build", "-t", &tag, "-f"])
369→            .arg(&dockerfile_path)
370→            .arg(&tmp_dir)
371→            .stdout(std::process::Stdio::piped())
372→            .stderr(std::process::Stdio::piped())
373→            .output()
374→            .await;
375→
376→        // Clean up temp dir regardless of result.
377→        let _ = std::fs::remove_dir_all(&tmp_dir);
378→
379→        let output = output?;
380→        if !output.status.success() {
381→            let stderr = String::from_utf8_lossy(&output.stderr);
382→            return Err(Error::message(format!(
383→                "{} build failed for {tag}: {}",
384→                self.cli,
385→                stderr.trim()
386→            )));
387→        }
388→
389→        info!(tag, "pre-built sandbox image ready");
390→        Ok(Some(BuildImageResult { tag, built: true }))
391→    }
392→
393→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
394→        let name = self.container_name(id);
395→
396→        let mut args = vec!["exec".to_string()];
397→
398→        if let Some(ref dir) = opts.working_dir {
399→            args.extend(["-w".to_string(), dir.display().to_string()]);
400→        }
401→
402→        // Inject proxy env vars so traffic routes through the trusted-network
403→        // proxy running on the host.
404→        args.extend(self.proxy_exec_env_args());
405→
406→        for (k, v) in &opts.env {
407→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
408→        }
409→
410→        args.push(name);
411→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
412→
413→        let child = tokio::process::Command::new(self.cli)
414→            .args(&args)
415→            .stdout(std::process::Stdio::piped())
416→            .stderr(std::process::Stdio::piped())
417→            .stdin(std::process::Stdio::null())
418→            .spawn()?;
419→
420→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
421→
422→        match result {
423→            Ok(Ok(output)) => {
424→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
425→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
426→
427→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
428→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
429→
430→                Ok(ExecResult {
431→                    stdout,
432→                    stderr,
433→                    exit_code: output.status.code().unwrap_or(-1),
434→                })
435→            },
436→            Ok(Err(e)) => {
437→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
438→            },
439→            Err(_) => {
440→                return Err(Error::message(format!(
441→                    "{} exec timed out after {}s",
442→                    self.cli,
443→                    opts.timeout.as_secs()
444→                )));
445→            },
446→        }
447→    }
448→
449→    async fn read_file(
450→        &self,
451→        id: &SandboxId,
452→        file_path: &str,
453→        max_bytes: u64,
454→    ) -> Result<SandboxReadResult> {
455→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
456→            return native_host_read_file(
457→                host_path
458→                    .to_str()
459→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
460→                max_bytes,
461→            )
462→            .await;
463→        }
464→
465→        let container_name = self.container_name(id);
466→        oci_container_read_file(self.cli, &container_name, file_path, max_bytes).await
467→    }
468→
469→    async fn write_file(
470→        &self,
471→        id: &SandboxId,
472→        file_path: &str,
473→        content: &[u8],
474→    ) -> Result<Option<serde_json::Value>> {
475→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
476→            return native_host_write_file(
477→                host_path
478→                    .to_str()
479→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
480→                content,
481→            )
482→            .await;
483→        }
484→
485→        let container_name = self.container_name(id);
486→        oci_container_write_file(self.cli, &container_name, file_path, content).await
487→    }
488→
489→    async fn list_files(&self, id: &SandboxId, root: &str) -> Result<SandboxListFilesResult> {
490→        if let Some(host_path) = self.mounted_host_path(id, root) {
491→            let host_files = native_host_list_files(
492→                host_path
493→                    .to_str()
494→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
495→            )
496→            .await?;
497→            return remap_host_list_result_to_guest(root, &host_path, host_files);
498→        }
499→
500→        let container_name = self.container_name(id);
501→        oci_container_list_files(self.cli, &container_name, root).await
502→    }
503→
504→    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
505→        let name = self.container_name(id);
506→        let _ = tokio::process::Command::new(self.cli)
507→            .args(["rm", "-f", &name])
508→            .output()
509→            .await;
510→        Ok(())
511→    }
512→}
