562→/// Return `true` when the installed Podman version supports `host-gateway`
563→/// in `--add-host` (added in Podman 5.0).
564→pub(crate) fn podman_supports_host_gateway() -> bool {
565→    let Ok(output) = std::process::Command::new("podman")
566→        .args(["version", "--format", "{{.Client.Version}}"])
567→        .output()
568→    else {
569→        return false;
570→    };
571→    let version_str = String::from_utf8_lossy(&output.stdout);
572→    let major: u32 = version_str
573→        .trim()
574→        .split('.')
575→        .next()
576→        .and_then(|s| s.parse().ok())
577→        .unwrap_or(0);
578→    major >= 5
579→}
580→
581→/// Resolve the host IP that a Podman container (< 5.0) can use to reach the
582→/// host.  Rootless Podman defaults to slirp4netns where the host is always
583→/// `10.0.2.2`.  Rootful Podman uses a bridge network whose gateway we query
584→/// with `podman network inspect`.
585→pub(crate) fn podman_resolve_host_ip() -> Option<String> {
586→    let rootless = std::process::Command::new("podman")
587→        .args(["info", "--format", "{{.Host.Security.Rootless}}"])
588→        .output()
589→        .ok()
590→        .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string());
591→
592→    if rootless.as_deref() == Some("true") {
593→        // slirp4netns (default rootless network before Podman 5.0) maps the
594→        // host to 10.0.2.2.
595→        return Some("10.0.2.2".to_string());
596→    }
597→
598→    // Rootful — ask for the gateway of the default "podman" network.
599→    let output = std::process::Command::new("podman")
600→        .args([
601→            "network",
602→            "inspect",
603→            "podman",
604→            "--format",
605→            "{{(index .Subnets 0).Gateway}}",
606→        ])
607→        .output()
608→        .ok()?;
609→    let gateway = String::from_utf8_lossy(&output.stdout).trim().to_string();
610→    if gateway.is_empty() {
611→        None
612→    } else {
613→        Some(gateway)
614→    }
615→}
