 20→pub(crate) fn sandbox_image_dockerfile(base: &str, packages: &[String]) -> String {
 21→    let pkg_list = canonical_sandbox_packages(packages).join(" ");
 22→    format!(
 23→        "FROM {base}\n\
 24→RUN apt-get update -qq && apt-get install -y -qq {pkg_list} \
 25→    && mkdir -p {SANDBOX_HOME_DIR}\n\
 26→RUN if command -v corepack >/dev/null 2>&1; then corepack enable; fi\n\
 27→RUN if command -v go >/dev/null 2>&1; then \
 28→        GOBIN=/usr/local/bin go install {GOGCLI_MODULE_PATH}@{GOGCLI_VERSION} \
 29→        && ln -sf /usr/local/bin/gog /usr/local/bin/gogcli; \
 30→    fi\n\
 31→RUN curl -fsSL https://mise.jdx.dev/install.sh | sh \
 32→    && echo 'export PATH=\"$HOME/.local/bin:$PATH\"' >> /etc/profile.d/mise.sh\n\
 33→ENV HOME={SANDBOX_HOME_DIR}\n\
 34→ENV PATH={SANDBOX_HOME_DIR}/.local/bin:/root/.local/bin:$PATH\n\
 35→WORKDIR {SANDBOX_HOME_DIR}\n"
 36→    )
 37→}
