 73→    if let Some(volume) = home_volume {
 74→        args.extend(["--volume".to_string(), volume.to_string()]);
 75→    }
 76→
 77→    args.push(image.to_string());
 78→    args.extend([
 79→        "sh".to_string(),
 80→        "-c".to_string(),
 81→        apple_container_bootstrap_command(),
 82→    ]);
 83→    args
