121→/// Compute the content-hash tag for a pre-built sandbox image.
122→/// Pure function — independent of any specific container CLI.
123→pub fn sandbox_image_tag(repo: &str, base: &str, packages: &[String]) -> String {
124→    let dockerfile = sandbox_image_dockerfile(base, packages);
125→    let digest = Sha256::digest(dockerfile.as_bytes());
126→    format!("{repo}:{digest:x}")
127→}
128→
129→pub(crate) fn is_sandbox_image_tag(tag: &str) -> bool {
130→    let Some((repo, _)) = tag.split_once(':') else {
131→        return false;
132→    };
133→    repo.ends_with("-sandbox")
134→}
135→
136→/// Return the deterministic image tag for the current sandbox config when the
137→/// requested image points to a local pre-built sandbox repository.
138→///
139→/// This allows recover-on-demand behavior when users delete local pre-built
140→/// images from the UI while Moltis is still running.
141→pub(crate) fn rebuildable_sandbox_image_tag(
142→    requested_image: &str,
143→    image_repo: &str,
144→    base_image: &str,
145→    packages: &[String],
146→) -> Option<String> {
147→    if packages.is_empty() {
148→        return None;
149→    }
150→    if !requested_image.starts_with(&format!("{image_repo}:")) {
151→        return None;
152→    }
153→    Some(sandbox_image_tag(image_repo, base_image, packages))
154→}
