298→/// Remove a specific `<instance>-sandbox:*` image.
299→pub async fn remove_sandbox_image(tag: &str) -> Result<()> {
300→    if !is_sandbox_image_tag(tag) {
301→        return Err(Error::message(format!(
302→            "refusing to remove non-sandbox image: {tag}"
303→        )));
304→    }
305→    // OCI-compatible CLIs (docker, podman) + Apple Container.
306→    let all_clis: Vec<&str> = OCI_COMPATIBLE_CLIS
307→        .iter()
308→        .copied()
309→        .chain(std::iter::once("container"))
310→        .collect();
311→    for cli in &all_clis {
312→        if !is_cli_available(cli) {
313→            continue;
314→        }
315→        if sandbox_image_exists(cli, tag).await {
316→            // Apple Container uses `image delete`, Docker/Podman use `image rm`.
317→            let subcmd = if *cli == "container" {
318→                "delete"
319→            } else {
320→                "rm"
321→            };
322→            let output = tokio::process::Command::new(cli)
323→                .args(["image", subcmd, tag])
324→                .output()
325→                .await?;
326→            if !output.status.success() {
327→                let stderr = String::from_utf8_lossy(&output.stderr);
328→                return Err(Error::message(format!(
329→                    "{cli} image {subcmd} failed for {tag}: {}",
330→                    stderr.trim()
331→                )));
332→            }
333→        }
334→    }
335→    Ok(())
336→}
337→
338→/// Remove all local `<instance>-sandbox:*` images.
339→pub async fn clean_sandbox_images() -> Result<usize> {
340→    let images = list_sandbox_images().await?;
341→    let count = images.len();
342→    for img in &images {
343→        remove_sandbox_image(&img.tag).await?;
344→    }
345→    Ok(count)
346→}
