573→/// Disk usage summary from the container runtime.
574→#[derive(Debug, Clone, Serialize)]
575→pub struct ContainerDiskUsage {
576→    pub containers_total: u64,
577→    pub containers_active: u64,
578→    pub containers_size_bytes: u64,
579→    pub containers_reclaimable_bytes: u64,
580→    pub images_total: u64,
581→    pub images_active: u64,
582→    pub images_size_bytes: u64,
583→}
