585→/// Query container runtime disk usage.
586→///
587→/// Uses `container system df --format json` for Apple Container,
588→/// falls back to `docker system df --format json` for Docker.
589→pub async fn container_disk_usage() -> Result<ContainerDiskUsage> {
590→    // Try Apple Container first.
591→    if is_cli_available("container") {
592→        let output = tokio::process::Command::new("container")
593→            .args(["system", "df", "--format", "json"])
594→            .output()
595→            .await;
596→        if let Ok(output) = output
597→            && output.status.success()
598→        {
599→            let stdout = String::from_utf8_lossy(&output.stdout);
600→            if let Ok(json) = serde_json::from_str::<serde_json::Value>(&stdout) {
601→                let c = json.get("containers").cloned().unwrap_or_default();
602→                let i = json.get("images").cloned().unwrap_or_default();
603→                return Ok(ContainerDiskUsage {
604→                    containers_total: c.get("total").and_then(|v| v.as_u64()).unwrap_or(0),
605→                    containers_active: c.get("active").and_then(|v| v.as_u64()).unwrap_or(0),
606→                    containers_size_bytes: c
607→                        .get("sizeInBytes")
608→                        .and_then(|v| v.as_u64())
609→                        .unwrap_or(0),
610→                    containers_reclaimable_bytes: c
611→                        .get("reclaimable")
612→                        .and_then(|v| v.as_u64())
613→                        .unwrap_or(0),
614→                    images_total: i.get("total").and_then(|v| v.as_u64()).unwrap_or(0),
615→                    images_active: i.get("active").and_then(|v| v.as_u64()).unwrap_or(0),
616→                    images_size_bytes: i.get("sizeInBytes").and_then(|v| v.as_u64()).unwrap_or(0),
617→                });
618→            }
619→        }
620→    }
621→
622→    // Fallback: Docker/Podman `<cli> system df --format json` (one JSON per line per type).
623→    for cli in OCI_COMPATIBLE_CLIS {
624→        if !is_cli_available(cli) {
625→            continue;
626→        }
627→        let output = tokio::process::Command::new(cli)
628→            .args(["system", "df", "--format", "{{json .}}"])
629→            .output()
630→            .await;
631→        if let Ok(output) = output
632→            && output.status.success()
633→        {
634→            let stdout = String::from_utf8_lossy(&output.stdout);
635→            let mut usage = ContainerDiskUsage {
636→                containers_total: 0,
637→                containers_active: 0,
638→                containers_size_bytes: 0,
639→                containers_reclaimable_bytes: 0,
640→                images_total: 0,
641→                images_active: 0,
642→                images_size_bytes: 0,
643→            };
644→            for line in stdout.lines() {
645→                if let Ok(json) = serde_json::from_str::<serde_json::Value>(line.trim()) {
646→                    let rtype = json.get("Type").and_then(|v| v.as_str()).unwrap_or("");
647→                    let total = json.get("TotalCount").and_then(|v| v.as_u64()).unwrap_or(0);
648→                    let active = json.get("Active").and_then(|v| v.as_u64()).unwrap_or(0);
649→                    let size = json.get("Size").and_then(|v| v.as_u64()).unwrap_or(0);
650→                    let reclaimable = json
651→                        .get("Reclaimable")
652→                        .and_then(|v| v.as_u64())
653→                        .unwrap_or(0);
654→                    match rtype {
655→                        "Containers" => {
656→                            usage.containers_total = total;
657→                            usage.containers_active = active;
658→                            usage.containers_size_bytes = size;
659→                            usage.containers_reclaimable_bytes = reclaimable;
660→                        },
661→                        "Images" => {
662→                            usage.images_total = total;
663→                            usage.images_active = active;
664→                            usage.images_size_bytes = size;
665→                        },
666→                        _ => {},
667→                    }
668→                }
669→            }
670→            return Ok(usage);
671→        }
672→    }
673→
674→    Err(Error::message("no container CLI available for disk usage"))
675→}
