864→pub(crate) fn apple_container_status_from_inspect(stdout: &str) -> Option<&'static str> {
865→    let inspect = stdout.trim();
866→    if inspect.is_empty() || inspect == "[]" {
867→        return None;
868→    }
869→
870→    if inspect.contains(r#""status":"running""#) {
871→        return Some("running");
872→    }
873→
874→    if inspect.contains(r#""status":"stopped""#) || inspect.contains(r#""status":"exited""#) {
875→        return Some("stopped");
876→    }
877→
878→    None
879→}
