933→/// Return the name of the container CLI to use for OCI image operations
934→/// (`docker run`, `docker build`, etc.).
935→///
936→/// Prefers `podman` (daemonless) when available, falls back to `docker`.
937→/// The result is cached after the first call.
938→pub fn container_cli() -> &'static str {
939→    static CLI: std::sync::OnceLock<&str> = std::sync::OnceLock::new();
940→    CLI.get_or_init(|| {
941→        if is_cli_available("podman") {
942→            "podman"
943→        } else {
944→            "docker"
945→        }
946→    })
947→}
