 33→pub(crate) fn configured_host_data_dir(config: &SandboxConfig) -> Option<PathBuf> {
 34→    let guest_data_dir = moltis_config::data_dir();
 35→    let path = config
 36→        .host_data_dir
 37→        .as_ref()
 38→        .filter(|path| !path.as_os_str().is_empty())?;
