 45→pub(crate) fn read_trimmed_file(path: &str) -> Option<String> {
 46→    std::fs::read_to_string(path)
 47→        .ok()
 48→        .map(|contents| contents.trim().to_string())
 49→        .filter(|contents| !contents.is_empty())
 50→}
