 52→pub(crate) fn normalize_cgroup_container_ref(segment: &str) -> Option<String> {
 53→    let mut value = segment.trim();
 54→    if value.is_empty() {
 55→        return None;
 56→    }
 57→    if let Some(stripped) = value.strip_suffix(".scope") {
 58→        value = stripped;
 59→    }
 60→    for prefix in ["docker-", "libpod-", "cri-containerd-"] {
 61→        if let Some(stripped) = value.strip_prefix(prefix) {
 62→            value = stripped;
 63→            break;
 64→        }
 65→    }
 66→    if value.len() < 12 || !value.chars().all(|ch| ch.is_ascii_hexdigit()) {
 67→        return None;
 68→    }
 69→    Some(value.to_string())
 70→}
