 72→pub(crate) fn current_container_references() -> Vec<String> {
 73→    let mut refs = Vec::new();
 74→    let mut seen = HashSet::new();
 75→    for candidate in [
 76→        std::env::var("HOSTNAME").ok(),
 77→        read_trimmed_file("/etc/hostname"),
 78→    ]
 79→    .into_iter()
 80→    .flatten()
 81→    {
 82→        if seen.insert(candidate.clone()) {
 83→            refs.push(candidate);
 84→        }
 85→    }
 86→    if let Ok(cgroup) = std::fs::read_to_string("/proc/self/cgroup") {
 87→        for candidate in cgroup
 88→            .lines()
 89→            .flat_map(|line| line.split(['/', ':']))
 90→            .filter_map(normalize_cgroup_container_ref)
 91→        {
 92→            if seen.insert(candidate.clone()) {
 93→                refs.push(candidate);
 94→            }
 95→        }
 96→    }
 97→    refs
 98→}
