 36→/// Docker/Podman-based sandbox implementation.
 37→///
 38→/// The `cli` field selects the container CLI binary (`"docker"` or `"podman"`).
 39→/// Podman's CLI is a drop-in replacement for Docker, so both backends share
 40→/// this single implementation.
 41→pub struct DockerSandbox {
 42→    pub config: SandboxConfig,
 43→    cli: &'static str,
 44→    backend_label: &'static str,
 45→}
 46→
 47→impl DockerSandbox {
 48→    pub fn new(config: SandboxConfig) -> Self {
 49→        Self {
 50→            config,
 51→            cli: "docker",
 52→            backend_label: "docker",
 53→        }
 54→    }
 55→
 56→    pub fn podman(config: SandboxConfig) -> Self {
 57→        Self {
 58→            config,
 59→            cli: "podman",
 60→            backend_label: "podman",
 61→        }
 62→    }
 63→
 64→    fn image(&self) -> &str {
 65→        self.config
 66→            .image
 67→            .as_deref()
 68→            .unwrap_or(DEFAULT_SANDBOX_IMAGE)
 69→    }
 70→
 71→    fn container_prefix(&self) -> &str {
 72→        self.config
 73→            .container_prefix
 74→            .as_deref()
 75→            .unwrap_or("moltis-sandbox")
 76→    }
 77→
 78→    pub(crate) fn container_name(&self, id: &SandboxId) -> String {
 79→        format!("{}-{}", self.container_prefix(), id.key)
 80→    }
 81→
 82→    fn image_repo(&self) -> &str {
