 86→    fn mounted_host_path(&self, id: &SandboxId, guest_path: &str) -> Option<std::path::PathBuf> {
 87→        let guest_path = std::path::Path::new(guest_path);
 88→        resolve_workspace_guest_path_on_host(&self.config, Some(self.cli), guest_path).or_else(
 89→            || {
 90→                resolve_home_persistence_guest_path_on_host(
