263→#[async_trait]
264→impl Sandbox for DockerSandbox {
265→    fn backend_name(&self) -> &'static str {
266→        self.backend_label
267→    }
268→
269→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
270→        let name = self.container_name(id);
271→
272→        // Check if container already running.
273→        let check = tokio::process::Command::new(self.cli)
274→            .args(["inspect", "--format", "{{.State.Running}}", &name])
275→            .output()
276→            .await;
277→
278→        if let Ok(output) = check {
279→            let stdout = String::from_utf8_lossy(&output.stdout);
280→            if stdout.trim() == "true" {
281→                return Ok(());
282→            }
283→        }
284→
285→        // Resolve image first so we know whether it's prebuilt (affects hardening).
286→        let requested_image = image_override.unwrap_or_else(|| self.image());
287→        let image = self.resolve_local_image(requested_image).await?;
288→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
289→
290→        // Start a new container.
291→        let mut args = vec![
292→            "run".to_string(),
293→            "-d".to_string(),
294→            "--name".to_string(),
295→            name.clone(),
296→        ];
297→
298→        args.extend(self.network_run_args());
299→
300→        if let Some(ref tz) = self.config.timezone {
301→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
302→        }
303→
304→        args.extend(self.resource_args());
305→        args.extend(Self::hardening_args(is_prebuilt));
306→        args.extend(self.workspace_args());
307→        args.extend(self.home_persistence_args(id)?);
308→
309→        args.push(image.clone());
310→        args.extend(["sleep".to_string(), "infinity".to_string()]);
311→
312→        let output = tokio::process::Command::new(self.cli)
313→            .args(&args)
314→            .output()
315→            .await?;
316→
317→        if !output.status.success() {
318→            let stderr = String::from_utf8_lossy(&output.stderr);
319→            return Err(Error::message(format!(
320→                "{} run failed: {}",
321→                self.cli,
322→                stderr.trim()
323→            )));
324→        }
325→
326→        // Skip provisioning if the image is a pre-built instance sandbox image
327→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
328→        if !is_prebuilt {
329→            provision_packages(self.cli, &name, &self.config.packages).await?;
330→        }
331→
332→        Ok(())
333→    }
334→
335→    async fn build_image(
336→        &self,
337→        base: &str,
338→        packages: &[String],
339→    ) -> Result<Option<BuildImageResult>> {
340→        if packages.is_empty() {
341→            return Ok(None);
342→        }
343→
344→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
345→
346→        // Check if image already exists.
347→        if sandbox_image_exists(self.cli, &tag).await {
348→            info!(
349→                tag,
350→                "pre-built sandbox image already exists, skipping build"
351→            );
352→            return Ok(Some(BuildImageResult { tag, built: false }));
353→        }
354→
355→        // Generate Dockerfile in a temp dir.
356→        let tmp_dir =
357→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
358→        std::fs::create_dir_all(&tmp_dir)?;
359→
360→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
361→        let dockerfile = sandbox_image_dockerfile(base, packages);
362→        let dockerfile_path = tmp_dir.join("Dockerfile");
363→        std::fs::write(&dockerfile_path, &dockerfile)?;
364→
365→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
366→
367→        let output = tokio::process::Command::new(self.cli)
368→            .args(["build", "-t", &tag, "-f"])
369→            .arg(&dockerfile_path)
370→            .arg(&tmp_dir)
371→            .stdout(std::process::Stdio::piped())
372→            .stderr(std::process::Stdio::piped())
373→            .output()
374→            .await;
375→
376→        // Clean up temp dir regardless of result.
377→        let _ = std::fs::remove_dir_all(&tmp_dir);
378→
379→        let output = output?;
380→        if !output.status.success() {
381→            let stderr = String::from_utf8_lossy(&output.stderr);
382→            return Err(Error::message(format!(
383→                "{} build failed for {tag}: {}",
384→                self.cli,
385→                stderr.trim()
386→            )));
387→        }
388→
389→        info!(tag, "pre-built sandbox image ready");
390→        Ok(Some(BuildImageResult { tag, built: true }))
391→    }
392→
393→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
394→        let name = self.container_name(id);
395→
396→        let mut args = vec!["exec".to_string()];
397→
398→        if let Some(ref dir) = opts.working_dir {
399→            args.extend(["-w".to_string(), dir.display().to_string()]);
400→        }
401→
402→        // Inject proxy env vars so traffic routes through the trusted-network
403→        // proxy running on the host.
404→        args.extend(self.proxy_exec_env_args());
405→
406→        for (k, v) in &opts.env {
407→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
408→        }
409→
410→        args.push(name);
411→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
412→
413→        let child = tokio::process::Command::new(self.cli)
414→            .args(&args)
415→            .stdout(std::process::Stdio::piped())
416→            .stderr(std::process::Stdio::piped())
417→            .stdin(std::process::Stdio::null())
418→            .spawn()?;
419→
420→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
421→
422→        match result {
423→            Ok(Ok(output)) => {
424→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
425→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
426→
427→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
428→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
429→
430→                Ok(ExecResult {
431→                    stdout,
432→                    stderr,
433→                    exit_code: output.status.code().unwrap_or(-1),
434→                })
435→            },
436→            Ok(Err(e)) => {
437→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
438→            },
439→            Err(_) => {
440→                return Err(Error::message(format!(
441→                    "{} exec timed out after {}s",
442→                    self.cli,
443→                    opts.timeout.as_secs()
444→                )));
445→            },
446→        }
447→    }
